// ===== Auth & API State =====
const TOTAL_WORDS = 1460;
const AUTH_KEY = 'vocab-app-auth-v1';

let auth = JSON.parse(localStorage.getItem(AUTH_KEY) || 'null');
let viewingUserId = null;
let currentState = null;
let summaryCache = null;
let isViewingSelf = true;
let selectedLoginUser = null;
let dictationMode = 'cn';
let viewingDay = null;  // 预览模式：null=正常，number=预读某一天（不影响 currentDay）

const USER_LABELS = {
  gao: { name: '哥哥', grade: '高一', role: '用户' },
  di: { name: '弟弟', grade: '三年级', role: '用户' },
  admin: { name: '管理员', grade: '', role: '管理员' }
};

function displayUserName(id, fallback) {
  return (USER_LABELS[id] && USER_LABELS[id].name) || fallback || id;
}
function displayUserGrade(id, fallback) {
  return (USER_LABELS[id] && USER_LABELS[id].grade) || fallback || '';
}
function displayRole(role) {
  return role === 'admin' ? '管理员' : '用户';
}

function wordId(w) {
  const idx = w.themeIdx != null ? w.themeIdx : '';
  return w.theme + '|' + idx + '|' + w.word;
}
function legacyWordId(w) { return w.theme + '|' + w.word; }
function getWordState(u, w) {
  if (!u || !u.states) return 'new';
  return u.states[wordId(w)] || u.states[legacyWordId(w)] || 'new';
}
function migrateStateKeys(state) {
  if (!state || !state.states || typeof state.states !== 'object') return false;
  let changed = false;
  const legacyIds = new Set();
  for (const day of SCHEDULE) {
    if (day.type !== '新词') continue;
    for (const w of day.words) {
      const id = wordId(w);
      const legacyId = legacyWordId(w);
      if (state.states[legacyId] && !state.states[id]) {
        state.states[id] = state.states[legacyId];
        changed = true;
      }
      legacyIds.add(legacyId);
    }
  }
  legacyIds.forEach(id => {
    if (state.states[id]) {
      delete state.states[id];
      changed = true;
    }
  });
  return changed;
}

async function api(path, opts = {}) {
  const headers = { 'Content-Type': 'application/json', ...(opts.headers || {}) };
  if (auth) headers.Authorization = 'Bearer ' + auth.token;
  let res, text, data;
  try {
    res = await fetch(path, { ...opts, headers });
    text = await res.text();
    data = text ? JSON.parse(text) : null;
  } catch (e) {
    throw new Error('network_error');
  }
  if (res.status === 401) {
    auth = null;
    localStorage.removeItem(AUTH_KEY);
    showLogin();
    throw new Error('unauthorized');
  }
  if (!res.ok) throw new Error((data && (data.message || data.error)) || ('http_' + res.status));
  return data;
}

async function login(userId, pin) {
  const r = await fetch('/api/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ userId, pin })
  });
  const data = await r.json().catch(() => ({}));
  if (!r.ok) throw new Error(data.message || data.error || 'login_failed');
  auth = {
    token: data.token,
    userId: data.user.id,
    role: data.user.role,
    name: displayUserName(data.user.id, data.user.name),
    grade: displayUserGrade(data.user.id, data.user.grade || '')
  };
  localStorage.setItem(AUTH_KEY, JSON.stringify(auth));
  return data.user;
}

function logout() {
  auth = null;
  localStorage.removeItem(AUTH_KEY);
  currentState = null;
  summaryCache = null;
  viewingUserId = null;
  isViewingSelf = true;
  viewingDay = null;
  showLogin();
}

async function loadMe() {
  const r = await api('/api/state');
  currentState = r.state;
  const migrated = migrateStateKeys(currentState);
  viewingUserId = auth.userId;
  isViewingSelf = true;
  if (migrated) await saveCurrentState();
  summaryCache = await api('/api/summary');
}

async function switchViewUser(uid) {
  // 切换用户时清掉预览模式，避免显示陈旧的预览 Day
  viewingDay = null;
  if (uid === auth.userId) {
    isViewingSelf = true;
    viewingUserId = auth.userId;
    const r = await api('/api/state');
    currentState = r.state;
    const migrated = migrateStateKeys(currentState);
    if (migrated) await saveCurrentState();
    summaryCache = await api('/api/summary');
  } else {
    if (auth.role !== 'admin') {
      showToast('无权查看其他用户');
      return;
    }
    const r = await api('/api/state?userId=' + encodeURIComponent(uid));
    currentState = r.state;
    migrateStateKeys(currentState);
    viewingUserId = uid;
    isViewingSelf = false;
    summaryCache = await api('/api/summary');
  }
  render();
}

async function saveCurrentState() {
  if (!currentState || !viewingUserId) return;
  await api('/api/state', {
    method: 'PUT',
    body: JSON.stringify({ userId: viewingUserId, state: currentState })
  });
}

// 兼容旧调用：fire-and-forget 保存到 API
function saveState() {
  if (!isViewingSelf) return;
  saveCurrentState().catch(err => {
    console.error('save failed', err);
    showToast('保存失败：' + err.message);
  });
}

async function refreshSummary() {
  try { summaryCache = await api('/api/summary'); } catch (e) { /* 静默 */ }
}

function getUserState() { return currentState; }

function escapeHTML(value) {
  return String(value ?? '').replace(/[&<>"']/g, ch => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;'
  }[ch]));
}

// ===== Stats =====
function getStats() {
  const u = getUserState();
  if (!u) return { mastered: 0, fuzzy: 0, learned: 0, total: TOTAL_WORDS };
  let mastered = 0, fuzzy = 0, learned = 0;
  for (const day of SCHEDULE) {
    if (day.type !== '新词') continue;
    for (const w of day.words) {
      const s = getWordState(u, w);
      if (s === 'mastered') { mastered++; learned++; }
      else if (s === 'fuzzy') { fuzzy++; learned++; }
    }
  }
  return { mastered, fuzzy, learned, total: TOTAL_WORDS };
}

// ===== Render =====
function render() {
  if (!currentState) return;
  const u = getUserState();
  const effDay = effectiveDay();
  const day = SCHEDULE[effDay - 1];

  // Header user info
  const headerName = displayUserName(auth.userId, auth.name);
  const headerGrade = displayUserGrade(auth.userId, auth.grade);
  document.getElementById('header-user-name').textContent = headerName + (headerGrade ? '（' + headerGrade + '）' : '');
  const roleEl = document.getElementById('header-user-role');
  roleEl.textContent = displayRole(auth.role);
  roleEl.className = 'user-info-role role-' + auth.role;

  // User switch (admin only)
  const userSwitch = document.getElementById('user-switch');
  if (auth.role === 'admin') {
    userSwitch.classList.remove('hidden');
    document.querySelectorAll('#user-switch .user-btn').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.user === viewingUserId);
    });
  } else {
    userSwitch.classList.add('hidden');
  }

  // Reset button (admin only — 哥哥弟弟不能有重置按钮)
  const resetBtn = document.getElementById('reset-btn');
  if (resetBtn) {
    if (auth.role === 'admin') {
      resetBtn.classList.remove('hidden');
    } else {
      resetBtn.classList.add('hidden');
    }
  }
  const importBtn = document.getElementById('import-btn');
  if (importBtn) {
    importBtn.classList.toggle('hidden', auth.role !== 'admin');
  }

  // Day nav (always shows the *displayed* day — which is the previewed day if any)
  document.getElementById('current-day').textContent = effDay;
  document.getElementById('prev-day').disabled = effDay <= 1;
  document.getElementById('next-day').disabled = effDay >= SCHEDULE.length;

  // Preview banner (Plan E)
  const previewBanner = document.getElementById('preview-banner');
  if (viewingDay != null) {
    previewBanner.classList.remove('hidden');
    document.getElementById('preview-day').textContent = effDay;
    document.getElementById('preview-return').textContent = u.currentDay;
  } else {
    previewBanner.classList.add('hidden');
  }

  // Fuzzy badge (Plan E)
  updateFuzzyBadge();

  const dayTypeEl = document.getElementById('day-type');
  dayTypeEl.className = 'day-type ' + (day.type === '新词' ? 'new' : day.type === '复习' ? 'review' : 'rest');
  dayTypeEl.textContent = day.type === '新词' ? '新词日' : day.type === '复习' ? '复习日' : '休息日';

  // Progress
  const stats = getStats();
  document.getElementById('mastered-count').textContent = stats.mastered;
  document.getElementById('progress-percent').textContent = (stats.mastered / stats.total * 100).toFixed(1) + '%';
  document.getElementById('progress-fill').style.width = (stats.mastered / stats.total * 100) + '%';

  // Theme header
  const themeHeader = document.getElementById('theme-header');
  if (day.type === '新词') {
    const themeRanges = {};
    day.words.forEach(w => {
      if (!themeRanges[w.theme]) themeRanges[w.theme] = [w.themeIdx, w.themeIdx];
      else themeRanges[w.theme][1] = w.themeIdx;
    });
    const desc = Object.entries(themeRanges)
      .map(([t, [s, e]]) => `<strong>${t}</strong>（${s}${s !== e ? '-' + e : ''}）`)
      .join(' + ');
    themeHeader.innerHTML = '📖 ' + desc;
  } else if (day.type === '复习') {
    themeHeader.innerHTML = '🔁 复习 ' + (day.themes || []).map(t => `<strong>${t}</strong>`).join(' · ');
  } else {
    themeHeader.innerHTML = '😌 休息日';
  }

  // Content
  const content = document.getElementById('content-area');
  content.innerHTML = '';
  if (day.type === '新词') {
    renderNewDay(content, day);
  } else if (day.type === '复习') {
    renderReviewDay(content, day);
  } else {
    renderRestDay(content, day);
  }

  // Role-specific sections
  renderRoleExtras();

  // Viewing banner (admin viewing others)
  let banner = document.getElementById('viewing-banner');
  if (!isViewingSelf) {
    if (!banner) {
      banner = document.createElement('div');
      banner.id = 'viewing-banner';
      banner.className = 'viewing-banner';
      const main = document.querySelector('main');
      main.insertBefore(banner, main.firstChild);
    }
    const target = summaryCache && summaryCache[viewingUserId];
    banner.textContent = '👁 你正在以管理员身份查看「' + displayUserName(viewingUserId, target && target.name) + '」的进度（只读）';
    banner.classList.remove('hidden');
  } else if (banner) {
    banner.classList.add('hidden');
  }
}

function renderRoleExtras() {
  // Peers (user role) - only percentages
  const peersEl = document.getElementById('peers-section');
  if (auth.role === 'user' && summaryCache) {
    const peers = Object.entries(summaryCache)
      .filter(([id]) => id !== auth.userId)
      .map(([id, p]) => {
        const percent = TOTAL_WORDS ? (p.mastered / TOTAL_WORDS * 100) : 0;
        return { id, name: escapeHTML(displayUserName(id, p.name)), percent, mastered: p.mastered, fuzzy: p.fuzzy };
      });
    if (peers.length > 0) {
      peersEl.classList.remove('hidden');
      peersEl.innerHTML = '<h3>👀 队友进度</h3>' + peers.map(p => (
        '<div class="peer-row">' +
          '<span class="peer-name">' + p.name + '</span>' +
          '<div class="peer-bar"><div class="peer-fill" style="width:' + p.percent.toFixed(1) + '%"></div></div>' +
          '<span class="peer-pct">' + p.percent.toFixed(1) + '%</span>' +
        '</div>'
      )).join('');
    } else {
      peersEl.classList.add('hidden');
    }
  } else {
    peersEl.classList.add('hidden');
  }

  // Admin section - all users with details
  const adminEl = document.getElementById('admin-section');
  if (auth.role === 'admin' && summaryCache) {
    const all = Object.entries(summaryCache).map(([id, p]) => {
      const percent = TOTAL_WORDS ? (p.mastered / TOTAL_WORDS * 100) : 0;
      return Object.assign({}, p, {
        id: escapeHTML(id),
        rawId: id,
        name: escapeHTML(displayUserName(id, p.name)),
        role: p.role,
        grade: escapeHTML(displayUserGrade(id, p.grade || '')),
        percent
      });
    });
    adminEl.classList.remove('hidden');
    adminEl.innerHTML = '<h3>🔑 所有用户详情</h3>' + all.map(p => (
      '<div class="admin-user-card ' + (p.rawId === viewingUserId ? 'selected' : '') + '">' +
        '<div class="admin-user-head">' +
          '<span class="admin-user-name">' + p.name + '</span>' +
          '<span class="admin-user-tag">' + (p.role === 'admin' ? '管理员' : (p.grade || '用户')) + '</span>' +
          '<button class="text-btn admin-jump" data-uid="' + p.id + '">' + (p.rawId === viewingUserId ? '当前查看' : '查看') + '</button>' +
        '</div>' +
        '<div class="admin-user-bar"><div class="admin-user-fill" style="width:' + p.percent.toFixed(1) + '%"></div></div>' +
        '<div class="admin-user-stats">' +
          '已掌握 <strong>' + p.mastered + '</strong> · 模糊 <strong>' + p.fuzzy + '</strong> · 当前 Day <strong>' + (p.currentDay != null ? p.currentDay : '-') + '</strong> · 进度 <strong>' + p.percent.toFixed(1) + '%</strong>' +
        '</div>' +
      '</div>'
    )).join('');
    adminEl.querySelectorAll('.admin-jump').forEach(b => {
      b.addEventListener('click', () => switchViewUser(b.dataset.uid));
    });
  } else {
    adminEl.classList.add('hidden');
  }
}

function renderNewDay(container, day) {
  const u = getUserState();
  const list = document.createElement('div');
  list.className = 'word-list';

  day.words.forEach((w, i) => {
    const id = wordId(w);
    const legacyId = legacyWordId(w);
    const attrId = escapeHTML(id);
    const attrLegacyId = escapeHTML(legacyId);
    const s = getWordState(u, w);
    const card = document.createElement('div');
    card.className = 'word-card ' + s;
    card.setAttribute('data-word', w.word);
    card.innerHTML = (
      '<div class="word-idx">' + (i + 1) + '</div>' +
      '<div class="word-info">' +
        '<div class="word-en">' + w.word + '<span class="word-cn-inline">' + w.cn + '</span></div>' +
        (w.phrase ? '<div class="word-phrase">' + w.phrase + '</div>' : '<div class="word-phrase">&nbsp;</div>') +
      '</div>' +
      '<button class="state-btn ' + s + '" data-word-id="' + attrId + '" data-legacy-id="' + attrLegacyId + '" data-state="' + s + '" data-idx="' + i + '">' +
        (s === 'mastered' ? '✓' : s === 'fuzzy' ? '⭐' : '○') +
      '</button>'
    );
    list.appendChild(card);
  });
  container.appendChild(list);
}

function renderReviewDay(container, day) {
  const u = getUserState();
  const themes = day.themes || [];
  themes.forEach(theme => {
    const section = document.createElement('div');
    section.className = 'review-section';
    const themeWords = day.words.filter(w => w.theme === theme);
    let html = '<h3>📚 ' + theme + '</h3><div class="word-list">';
    themeWords.forEach((w, i) => {
      const id = wordId(w);
      const legacyId = legacyWordId(w);
      const attrId = escapeHTML(id);
      const attrLegacyId = escapeHTML(legacyId);
      const s = getWordState(u, w);
      html += (
        '<div class="word-card ' + s + '" data-word="' + escapeHTML(w.word) + '">' +
          '<div class="word-idx">' + (i + 1) + '</div>' +
          '<div class="word-info">' +
            '<div class="word-en">' + w.word + '<span class="word-cn-inline">' + w.cn + '</span></div>' +
            (w.phrase ? '<div class="word-phrase">' + w.phrase + '</div>' : '<div class="word-phrase">&nbsp;</div>') +
          '</div>' +
          '<button class="state-btn ' + s + '" data-word-id="' + attrId + '" data-legacy-id="' + attrLegacyId + '" data-state="' + s + '" data-idx="r' + i + '">' + (s === 'mastered' ? '✓' : s === 'fuzzy' ? '⭐' : '○') + '</button>' +
        '</div>'
      );
    });
    html += '</div>';
    section.innerHTML = html;
    container.appendChild(section);
  });

  const fuzzyWords = collectFuzzyWords(day);
  if (fuzzyWords.length > 0) {
    const fuzzySection = document.createElement('div');
    fuzzySection.className = 'fuzzy-section';
    let html = '<h3>⭐ 模糊回炉</h3><div class="word-list">';
    fuzzyWords.forEach((w, i) => {
      const id = wordId(w);
      const legacyId = legacyWordId(w);
      const attrId = escapeHTML(id);
      const attrLegacyId = escapeHTML(legacyId);
      html += (
        '<div class="word-card fuzzy" data-word="' + escapeHTML(w.word) + '">' +
          '<div class="word-idx">' + (i + 1) + '</div>' +
          '<div class="word-info">' +
            '<div class="word-en">' + w.word + '<span class="word-cn-inline">' + w.cn + '</span></div>' +
            (w.phrase ? '<div class="word-phrase">' + w.phrase + '</div>' : '<div class="word-phrase">&nbsp;</div>') +
          '</div>' +
          '<button class="state-btn fuzzy" data-word-id="' + attrId + '" data-legacy-id="' + attrLegacyId + '" data-state="fuzzy">⭐</button>' +
        '</div>'
      );
    });
    html += '</div></div>';
    fuzzySection.innerHTML = html;
    container.appendChild(fuzzySection);
  }

  const dictBtn = document.createElement('button');
  dictBtn.className = 'action-btn';
  dictBtn.textContent = '🎧 听写测试 (5 词)';
  dictBtn.onclick = () => {
    if (viewingDay != null) {
      showToast('预览模式请先回到 Day ' + getUserState().currentDay + ' 再听写');
      return;
    }
    startDictation(day);
  };
  container.appendChild(dictBtn);
}

function collectFuzzyWords(day) {
  const u = getUserState();
  if (!u) return [];
  const result = [];
  const dayIdx = day.day - 1;
  const cycleStart = Math.floor(dayIdx / 7) * 7;
  for (let i = cycleStart; i < cycleStart + 5 && i < SCHEDULE.length; i++) {
    if (SCHEDULE[i].type !== '新词') continue;
    SCHEDULE[i].words.forEach(w => {
      if (getWordState(u, w) === 'fuzzy') {
        result.push(w);
      }
    });
  }
  return result;
}

function renderRestDay(container, day) {
  const rest = document.createElement('div');
  rest.className = 'rest-section rest-content';
  const tips = [
    '🎵 听英文儿歌 / 看英文动画（不背词，纯磨耳朵）',
    '📖 翻一翻这周背过的单词本',
    '🚶 出门走走，眼睛和脑子都休息',
    '✏️ 玩一玩单词游戏（Quizlet / 多邻国）'
  ];
  const tip = tips[Math.floor(Math.random() * tips.length)];
  rest.innerHTML = (
    '<div class="emoji">😌</div>' +
    '<h2>休息日</h2>' +
    '<p>今天不用背新词，<br>给大脑放个假。</p>' +
    '<div class="rest-tips"><strong>今天推荐：</strong><br>' + tip + '</div>'
  );
  container.appendChild(rest);
}

// ===== Plan E: Preview Mode / Search / Fuzzy Drawer / Day Jump =====

function effectiveDay() {
  if (!currentState) return 1;
  return viewingDay != null ? viewingDay : getUserState().currentDay;
}

function enterPreview(day) {
  const u = getUserState();
  if (!u) return;
  if (typeof day !== 'number' || isNaN(day)) return;
  if (day < 1) day = 1;
  if (day > SCHEDULE.length) day = SCHEDULE.length;
  viewingDay = day;
  render();
}

function exitPreview() {
  if (viewingDay == null) return;
  viewingDay = null;
  render();
}

// Get all fuzzy words across all days (with day attached)
function getAllFuzzyWords() {
  const u = getUserState();
  if (!u) return [];
  const result = [];
  SCHEDULE.forEach((day) => {
    if (day.type !== '新词') return;
    day.words.forEach(w => {
      if (getWordState(u, w) === 'fuzzy') {
        result.push(Object.assign({}, w, { day: day.day }));
      }
    });
  });
  return result;
}

function updateFuzzyBadge() {
  const count = getAllFuzzyWords().length;
  const badge = document.getElementById('fuzzy-count');
  if (badge) {
    badge.textContent = count;
    badge.classList.toggle('zero', count === 0);
  }
}

// ---- Search Modal ----
function openSearchModal() {
  if (!isViewingSelf) { showToast('只读模式，无法搜索'); return; }
  document.getElementById('search-modal').classList.remove('hidden');
  const input = document.getElementById('search-input');
  input.value = '';
  renderSearchResults('');
  setTimeout(() => input.focus(), 50);
}

function closeSearchModal() {
  document.getElementById('search-modal').classList.add('hidden');
}

function renderSearchResults(query) {
  const container = document.getElementById('search-results');
  if (!query || !query.trim()) {
    container.innerHTML = '<div class="search-empty">输入关键词开始搜索</div>';
    return;
  }
  const q = query.trim().toLowerCase();
  const allWords = [];
  SCHEDULE.forEach(day => {
    if (day.type !== '新词') return;
    day.words.forEach(w => allWords.push(Object.assign({}, w, { day: day.day })));
  });
  const matches = allWords.filter(w => {
    return w.word.toLowerCase().includes(q)
      || (w.cn || '').toLowerCase().includes(q)
      || (w.theme || '').toLowerCase().includes(q);
  });
  matches.sort((a, b) => a.day - b.day);
  const limited = matches.slice(0, 20);
  if (limited.length === 0) {
    container.innerHTML = '<div class="search-empty">没有匹配结果</div>';
    return;
  }
  container.innerHTML = limited.map(w => (
    '<div class="search-result-item" data-day="' + w.day + '" data-word="' + escapeHTML(w.word) + '">' +
      '<div style="flex:1"><div class="word-en">' + escapeHTML(w.word) + '</div>' +
      '<div class="word-cn">' + escapeHTML(w.cn || '') + '</div></div>' +
      '<span class="day-tag">Day ' + w.day + '</span>' +
    '</div>'
  )).join('');
  if (matches.length > 20) {
    container.innerHTML += '<div class="search-empty" style="padding:10px 16px;font-size:12px">仅显示前 20 条，共 ' + matches.length + ' 条匹配</div>';
  }
}

// ---- Fuzzy Drawer ----
function openFuzzyDrawer() {
  if (!isViewingSelf) { showToast('只读模式'); return; }
  renderFuzzyList();
  document.getElementById('fuzzy-drawer').classList.remove('hidden');
}

function closeFuzzyDrawer() {
  document.getElementById('fuzzy-drawer').classList.add('hidden');
}

function renderFuzzyList() {
  const list = getAllFuzzyWords().slice().sort((a, b) => a.word.localeCompare(b.word));
  const container = document.getElementById('fuzzy-list');
  const countEl = document.getElementById('fuzzy-drawer-count');
  countEl.textContent = '（' + list.length + '）';
  if (list.length === 0) {
    container.innerHTML = '<div class="fuzzy-empty">🎉 当前没有模糊词</div>';
    return;
  }
  container.innerHTML = list.map(w => (
    '<div class="fuzzy-item" data-day="' + w.day + '" data-word="' + escapeHTML(w.word) + '">' +
      '<div style="flex:1"><div class="word-en">' + escapeHTML(w.word) + '</div>' +
      '<div class="word-cn">' + escapeHTML(w.cn || '') + '</div></div>' +
      '<span class="day-tag">Day ' + w.day + '</span>' +
    '</div>'
  )).join('');
}

// ---- Day Jump Modal ----
function openDayJump() {
  if (!isViewingSelf) { showToast('只读模式'); return; }
  const input = document.getElementById('day-jump-input');
  input.value = '';
  document.getElementById('day-jump-modal').classList.remove('hidden');
  setTimeout(() => input.focus(), 50);
}

function closeDayJump() {
  document.getElementById('day-jump-modal').classList.add('hidden');
}

function doDayJump() {
  const input = document.getElementById('day-jump-input');
  const n = parseInt(input.value, 10);
  if (!n || n < 1 || n > SCHEDULE.length) {
    showToast('请输入 1-' + SCHEDULE.length + ' 之间的数字');
    return;
  }
  closeDayJump();
  enterPreview(n);
}

// ---- Pulse highlight on a word card ----
function pulseWord(day, word) {
  enterPreview(day);
  // Wait for render to complete (sync, but scroll needs rAF)
  setTimeout(() => {
    const sel = '.word-card[data-word="' + cssEscape(word) + '"]';
    const el = document.querySelector(sel);
    if (!el) return;
    el.scrollIntoView({ behavior: 'smooth', block: 'center' });
    el.classList.add('pulse-highlight');
    setTimeout(() => el.classList.remove('pulse-highlight'), 1600);
  }, 80);
}

function cssEscape(s) {
  return String(s).replace(/(["\\])/g, '\\$1');
}

// ===== State Cycle =====
function cycleState(id, btn) {
  const u = getUserState();
  if (!u) return;
  const legacyId = btn ? btn.dataset.legacyId : null;
  const cur = (btn && btn.dataset.state) || u.states[id] || (legacyId && u.states[legacyId]) || 'new';
  const next = cur === 'new' ? 'mastered' : cur === 'mastered' ? 'fuzzy' : 'new';
  if (next === 'new') {
    delete u.states[id];
  } else {
    u.states[id] = next;
  }
  if (legacyId && legacyId !== id) delete u.states[legacyId];
  saveState();
  render();
  refreshSummary().then(() => renderRoleExtras());
}

function clearState(id, btn) {
  const u = getUserState();
  if (!u) return;
  const legacyId = btn ? btn.dataset.legacyId : null;
  const cur = (btn && btn.dataset.state) || u.states[id] || (legacyId && u.states[legacyId]) || 'new';
  if (cur === 'fuzzy') {
    u.states[id] = 'mastered';
  } else if (cur === 'mastered') {
    delete u.states[id];
  } else {
    u.states[id] = 'mastered';
  }
  if (legacyId && legacyId !== id) delete u.states[legacyId];
  saveState();
  render();
  refreshSummary().then(() => renderRoleExtras());
}

// ===== Dictation =====
let dictationState = null;

function getDictationWords(day) {
  if (!day) return [];
  if (day.type === '新词') {
    return (day.words || []).filter(w => !w.isReviewItem);
  }
  const words = [];
  const dayIdx = day.day - 1;
  const cycleStart = Math.floor(dayIdx / 7) * 7;
  for (let i = cycleStart; i < cycleStart + 5 && i < SCHEDULE.length; i++) {
    if (SCHEDULE[i].type !== '新词') continue;
    words.push(...SCHEDULE[i].words.filter(w => !w.isReviewItem));
  }
  return words;
}

function setDictationMode(mode) {
  dictationMode = mode === 'audio' ? 'audio' : 'cn';
  document.querySelectorAll('.dictation-mode').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.mode === dictationMode);
  });
  if (dictationState && dictationState.idx < dictationState.total) {
    showDictationPrompt();
  }
}

function startDictation(day) {
  const candidates = getDictationWords(day);
  if (candidates.length === 0) {
    showToast('当前章节没有可听写的词');
    return;
  }
  dictationState = { picks: candidates, idx: 0, correct: 0, total: candidates.length, input: '' };
  document.getElementById('dictation-modal').classList.remove('hidden');
  document.getElementById('dictation-start').classList.remove('hidden');
  document.getElementById('dictation-replay').classList.add('hidden');
  document.getElementById('dictation-start').textContent = '开始';
  document.getElementById('dictation-prompt').textContent = '点击"开始"听写，本章节共 ' + dictationState.total + ' 词';
  document.getElementById('dictation-prompt').classList.remove('speaking');
  document.getElementById('dictation-input').value = '';
  document.getElementById('dictation-feedback').textContent = '';
  document.getElementById('dictation-feedback').className = 'dictation-feedback';
  document.getElementById('dictation-progress').textContent = '0 / ' + dictationState.total;
}

function showDictationPrompt() {
  const w = dictationState.picks[dictationState.idx];
  const prompt = document.getElementById('dictation-prompt');
  prompt.classList.remove('speaking');
  if (dictationMode === 'audio') {
    prompt.textContent = '听英文，写出英文单词';
    document.getElementById('dictation-replay').classList.remove('hidden');
    speakWord(w.word);
  } else {
    window.speechSynthesis && window.speechSynthesis.cancel();
    prompt.textContent = w.cn + (w.phrase ? ' ｜ ' + w.phrase : '');
    document.getElementById('dictation-replay').classList.add('hidden');
  }
}

function speakWord(word) {
  if (!('speechSynthesis' in window)) {
    showToast('浏览器不支持语音');
    return;
  }
  window.speechSynthesis.cancel();
  const u = new SpeechSynthesisUtterance(word);
  u.lang = 'en-US';
  u.rate = 0.85;
  u.pitch = 1;
  window.speechSynthesis.speak(u);
  const prompt = document.getElementById('dictation-prompt');
  prompt.textContent = '🔊 正在朗读英文，写出英文单词';
  prompt.classList.add('speaking');
}

function nextDictation() {
  if (!dictationState) return;
  if (dictationState.idx >= dictationState.total) {
    const score = Math.round(dictationState.correct / dictationState.total * 100);
    const prompt = document.getElementById('dictation-prompt');
    const fb = document.getElementById('dictation-feedback');
    prompt.textContent = '测试完成';
    prompt.classList.remove('speaking');
    fb.innerHTML = '<div class="dictation-result"><div class="dictation-result-score">' + score + '%</div><div>' + dictationState.correct + ' / ' + dictationState.total + ' 正确</div></div>';
    fb.className = 'dictation-feedback correct';
    document.getElementById('dictation-start').classList.remove('hidden');
    document.getElementById('dictation-start').textContent = '再来一次';
    document.getElementById('dictation-replay').classList.add('hidden');
    dictationState = null;
    return;
  }
  const w = dictationState.picks[dictationState.idx];
  document.getElementById('dictation-input').value = '';
  document.getElementById('dictation-input').disabled = false;
  document.getElementById('dictation-input').focus();
  document.getElementById('dictation-feedback').textContent = '';
  document.getElementById('dictation-feedback').className = 'dictation-feedback';
  document.getElementById('dictation-progress').textContent = (dictationState.idx + 1) + ' / ' + dictationState.total;
  document.getElementById('dictation-start').classList.add('hidden');
  showDictationPrompt();
}

function checkDictation() {
  if (!dictationState) return;
  const w = dictationState.picks[dictationState.idx];
  const input = document.getElementById('dictation-input').value.trim().toLowerCase();
  const correct = w.word.toLowerCase();
  const fb = document.getElementById('dictation-feedback');
  if (input === correct) {
    fb.textContent = '✓ 正确！';
    fb.className = 'dictation-feedback correct';
    dictationState.correct++;
    const u = getUserState();
    const id = wordId(w);
    const legacyId = legacyWordId(w);
    u.states[id] = 'mastered';
    if (legacyId !== id) delete u.states[legacyId];
    saveState();
    refreshSummary();
    setTimeout(() => {
      dictationState.idx++;
      nextDictation();
    }, 800);
  } else if (input === '') {
    // 空输入：忽略
  } else {
    fb.innerHTML = '✗ 正确拼写: <strong>' + w.word + '</strong> (' + w.cn + ')';
    fb.className = 'dictation-feedback wrong';
    setTimeout(() => {
      dictationState.idx++;
      nextDictation();
    }, 1800);
  }
}

function shuffle(arr) {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
}

function showToast(msg) {
  const t = document.createElement('div');
  t.className = 'toast';
  t.textContent = msg;
  document.body.appendChild(t);
  setTimeout(() => t.remove(), 2000);
}

// ===== Login UI =====
function showLogin() {
  document.getElementById('login-screen').classList.remove('hidden');
  document.getElementById('app').classList.add('hidden');
  document.getElementById('pin-input').value = '';
  document.getElementById('login-error').textContent = '';
}

function showApp() {
  document.getElementById('login-screen').classList.add('hidden');
  document.getElementById('app').classList.remove('hidden');
}

function selectLoginUser(userId) {
  selectedLoginUser = userId;
  document.querySelectorAll('.pick-btn').forEach(b => {
    b.classList.toggle('selected', b.dataset.user === userId);
  });
  document.getElementById('pin-input').value = '';
  document.getElementById('pin-input').focus();
  document.getElementById('login-error').textContent = '';
}

async function doLogin() {
  const pin = document.getElementById('pin-input').value.trim();
  const errEl = document.getElementById('login-error');
  errEl.textContent = '';
  if (!selectedLoginUser) {
    errEl.textContent = '请先选择身份';
    return;
  }
  if (!/^\d{4}$/.test(pin)) {
    errEl.textContent = 'PIN 必须为 4 位数字';
    return;
  }
  const btn = document.getElementById('login-btn');
  btn.disabled = true;
  btn.textContent = '登录中…';
  try {
    await login(selectedLoginUser, pin);
    showApp();
    await loadMe();
    render();
  } catch (e) {
    errEl.textContent = '登录失败：' + (e.message || '未知错误');
    auth = null;
  } finally {
    btn.disabled = false;
    btn.textContent = '登录';
    document.getElementById('pin-input').value = '';
  }
}

async function doReset() {
  // 防御性二次校验：重置仅限管理员（UI 已隐藏，但防 DevTools 误调）
  if (auth.role !== 'admin') {
    showToast('无权操作：仅管理员可重置进度');
    return;
  }
  let label = displayUserName(auth.userId, auth.name);
  if (!isViewingSelf) {
    const target = summaryCache && summaryCache[viewingUserId];
    label = displayUserName(viewingUserId, target && target.name);
  }
  if (!confirm('确定要重置「' + label + '」的所有进度吗？此操作不可撤销。')) return;
  try {
    let body = {};
    if (!isViewingSelf) {
      const adminConfirmPin = prompt('请输入管理员 PIN 以确认重置「' + label + '」');
      if (adminConfirmPin === null) return;
      if (!/^\d{4,8}$/.test(adminConfirmPin.trim())) {
        showToast('管理员 PIN 必须为 4-8 位数字');
        return;
      }
      body = { userId: viewingUserId, adminConfirmPin: adminConfirmPin.trim() };
    }
    const r = await api('/api/reset', { method: 'POST', body: JSON.stringify(body) });
    if (r && r.state) {
      currentState = r.state;
    } else {
      const r2 = await api('/api/state' + (isViewingSelf ? '' : '?userId=' + encodeURIComponent(viewingUserId)));
      currentState = r2.state;
    }
    render();
    showToast('已重置');
  } catch (e) {
    showToast('重置失败：' + e.message);
  }
}

function doExport() {
  const target = summaryCache && summaryCache[viewingUserId];
  const data = JSON.stringify({
    user: displayUserName(viewingUserId, target && target.name),
    userId: viewingUserId,
    exportedAt: new Date().toISOString(),
    state: currentState
  }, null, 2);
  const blob = new Blob([data], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const date = new Date().toISOString().slice(0, 10);
  a.href = url;
  a.download = 'vocab-backup-' + viewingUserId + '-' + date + '.json';
  a.click();
  URL.revokeObjectURL(url);
  showToast('已下载备份');
}

// ===== Event Handlers =====
// Login screen
document.querySelectorAll('.pick-btn').forEach(b => {
  b.addEventListener('click', () => selectLoginUser(b.dataset.user));
});
document.getElementById('login-btn').addEventListener('click', doLogin);
document.getElementById('pin-input').addEventListener('keydown', e => {
  if (e.key === 'Enter') doLogin();
});

document.querySelectorAll('.dictation-mode').forEach(btn => {
  btn.addEventListener('click', () => setDictationMode(btn.dataset.mode));
});

// Logout
document.getElementById('logout-btn').addEventListener('click', logout);

// Main app click handler
document.addEventListener('click', e => {
  // State button
  const btn = e.target.closest('.state-btn');
  if (btn) {
    const id = btn.dataset.wordId;
    if (!id) return;
    if (!isViewingSelf) {
      showToast('只读模式，无法修改');
      return;
    }
    if (viewingDay != null) {
      showToast('预览模式无法修改，请先回到 Day ' + getUserState().currentDay);
      return;
    }
    if (btn.classList.contains('fuzzy') && btn.textContent === '⭐') {
      const card = btn.closest('.word-card');
      if (card && card.classList.contains('fuzzy') && card.parentElement.parentElement.classList.contains('fuzzy-section')) {
        clearState(id, btn);
        return;
      }
    }
    cycleState(id, btn);
    return;
  }

  // Day nav (Plan E: works in preview mode by stepping viewingDay)
  if (e.target.closest('#prev-day')) {
    if (!isViewingSelf) { showToast('只读模式'); return; }
    if (viewingDay != null) {
      if (viewingDay > 1) { viewingDay--; render(); }
    } else {
      if (getUserState().currentDay > 1) {
        getUserState().currentDay--;
        saveState();
        render();
      }
    }
  }
  if (e.target.closest('#next-day')) {
    if (!isViewingSelf) { showToast('只读模式'); return; }
    if (viewingDay != null) {
      if (viewingDay < SCHEDULE.length) { viewingDay++; render(); }
    } else {
      if (getUserState().currentDay < SCHEDULE.length) {
        getUserState().currentDay++;
        saveState();
        render();
      }
    }
  }

  // Plan E: utility bar buttons
  if (e.target.closest('#search-btn')) { openSearchModal(); return; }
  if (e.target.closest('#fuzzy-btn')) { openFuzzyDrawer(); return; }
  if (e.target.closest('#day-jump-btn')) { openDayJump(); return; }
  if (e.target.closest('#exit-preview-btn')) { exitPreview(); return; }

  // Plan E: search/fuzzy result item click → preview + pulse
  const searchItem = e.target.closest('.search-result-item');
  if (searchItem) {
    const day = parseInt(searchItem.dataset.day, 10);
    const word = searchItem.dataset.word;
    closeSearchModal();
    pulseWord(day, word);
    return;
  }
  const fuzzyItem = e.target.closest('.fuzzy-item');
  if (fuzzyItem) {
    const day = parseInt(fuzzyItem.dataset.day, 10);
    const word = fuzzyItem.dataset.word;
    closeFuzzyDrawer();
    pulseWord(day, word);
    return;
  }

  // Plan E: modal close buttons
  const modalClose = e.target.closest('.modal-close');
  if (modalClose) {
    const which = modalClose.dataset.close;
    if (which === 'search') closeSearchModal();
    else if (which === 'day-jump') closeDayJump();
    return;
  }
  const drawerClose = e.target.closest('.drawer-close');
  if (drawerClose) {
    const which = drawerClose.dataset.close;
    if (which === 'fuzzy') closeFuzzyDrawer();
    return;
  }

  // Plan E: click outside modal-box to close
  const overlay = e.target.closest('.modal-overlay');
  if (overlay) {
    if (overlay.id === 'search-modal') closeSearchModal();
    else if (overlay.id === 'day-jump-modal') closeDayJump();
    return;
  }
  const drawerOverlay = e.target.closest('.drawer-overlay');
  if (drawerOverlay) {
    if (drawerOverlay.id === 'fuzzy-drawer') closeFuzzyDrawer();
    return;
  }

  // Admin user switch
  const userBtn = e.target.closest('#user-switch .user-btn');
  if (userBtn) {
    switchViewUser(userBtn.dataset.user);
    return;
  }

  // Footer
  if (e.target.closest('#export-btn')) doExport();
  if (e.target.closest('#import-btn')) {
    if (auth.role !== 'admin') {
      showToast('导入仅限管理员使用');
      return;
    }
    document.getElementById('import-file').click();
  }
  if (e.target.closest('#dictation-btn')) {
    if (!isViewingSelf) { showToast('只读模式'); return; }
    const u = getUserState();
    const day = SCHEDULE[u.currentDay - 1];
    startDictation(day);
  }
  if (e.target.closest('#reset-btn')) doReset();

  // Dictation modal
  if (e.target.closest('#dictation-start')) {
    if (!isViewingSelf) { showToast('只读模式'); return; }
    if (!dictationState || dictationState.idx >= dictationState.total) {
      const u = getUserState();
      const day = SCHEDULE[u.currentDay - 1];
      startDictation(day);
    }
    nextDictation();
  }
  if (e.target.closest('#dictation-replay')) {
    if (dictationState && dictationState.idx < dictationState.total) {
      speakWord(dictationState.picks[dictationState.idx].word);
    }
  }
  if (e.target.closest('#dictation-skip')) {
    if (dictationState) {
      dictationState.idx++;
      nextDictation();
    }
  }
  if (e.target.closest('#dictation-close')) {
    dictationState = null;
    document.getElementById('dictation-modal').classList.add('hidden');
    render();
  }
});

document.getElementById('dictation-input').addEventListener('keydown', e => {
  if (e.key === 'Enter') {
    if (dictationState && dictationState.idx < dictationState.total) {
      checkDictation();
    } else {
      nextDictation();
    }
  }
});

// Plan E: search input (live fuzzy search)
document.getElementById('search-input').addEventListener('input', e => {
  renderSearchResults(e.target.value);
});
document.getElementById('search-input').addEventListener('keydown', e => {
  if (e.key === 'Escape') closeSearchModal();
});

// Plan E: day-jump input (Enter to confirm)
document.getElementById('day-jump-input').addEventListener('keydown', e => {
  if (e.key === 'Enter') { doDayJump(); }
  else if (e.key === 'Escape') { closeDayJump(); }
});
document.getElementById('day-jump-confirm').addEventListener('click', doDayJump);
document.getElementById('day-jump-cancel').addEventListener('click', closeDayJump);

document.getElementById('import-file').addEventListener('change', e => {
  if (auth.role !== 'admin') {
    showToast('导入仅限管理员使用');
    e.target.value = '';
    return;
  }
  const file = e.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = ev => {
    try {
      const data = JSON.parse(ev.target.result);
      if (!data.state) {
        showToast('文件格式错误');
        return;
      }
      if (data.userId && data.userId !== viewingUserId) {
        showToast('导入文件与当前账号不匹配（期望 ' + viewingUserId + '）');
        return;
      }
      if (confirm('导入将覆盖「' + auth.name + '」的当前进度，确定吗？')) {
        currentState = data.state;
        saveState();
        render();
        showToast('导入成功 ✓');
      }
    } catch (err) {
      showToast('文件格式错误');
    }
  };
  reader.readAsText(file);
  e.target.value = '';
});

// ===== Init =====
(async function init() {
  if (auth) {
    showApp();
    try {
      await loadMe();
      render();
    } catch (e) {
      console.error('init failed', e);
      auth = null;
      localStorage.removeItem(AUTH_KEY);
      showLogin();
    }
  } else {
    showLogin();
  }
})();
